import React, { useState } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
import { Modal, Button } from 'react-bootstrap';

const ScheduleCalendar = ({ schedules }) => {
    const [modalShow, setModalShow] = useState(false);
    const [selectedEvent, setSelectedEvent] = useState(null);

    const events = schedules.map((schedule) => ({
        title: schedule.name,
        start: schedule.startDateTime,
        end: schedule.endDateTime,
        extendedProps: { // 추가 정보를 저장할 수 있음
            scheduleInfo: schedule.scheduleInfo,
            scheduleType: schedule.scheduleType,
            institutionId: schedule.institutionId,
        },
    }));

    const handleEventClick = (info) => {
        setSelectedEvent({
            title: info.event.title,
            scheduleInfo: info.event.extendedProps.scheduleInfo,
            start: info.event.start ? info.event.start.toISOString() : '시작일이 없습니다.',
            end: info.event.end ? info.event.end.toISOString() : '종료일이 없습니다.',
            scheduleType: info.event.extendedProps.scheduleType,
        });
        setModalShow(true);
    };

    const handleClose = () => setModalShow(false);

    return (
        <div>
            <h3>Schedules</h3>
            <FullCalendar
                plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
                initialView="dayGridMonth"
                headerToolbar={{
                    left: 'prev,next today',
                    center: 'title',
                    right: '',
                }}
                events={events}
                eventClick={handleEventClick} // 클릭 이벤트 처리기 등록
            />

            {/* 모달 */}
            <Modal show={modalShow} onHide={handleClose}>
                <Modal.Header closeButton>
                    <Modal.Title>상세 일정</Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    {selectedEvent ? (
                        <div>
                            <p>
                                <strong>이름:</strong> {selectedEvent.title}
                            </p>
                            <p>
                                <strong>일정 정보:</strong> {selectedEvent.scheduleInfo}
                            </p>
                            <p>
                                <strong>시작일:</strong> {selectedEvent.start}
                            </p>
                            <p>
                                <strong>종료일:</strong> {selectedEvent.end}
                            </p>
                        </div>
                    ) : (
                        <p>No details available.</p>
                    )}
                </Modal.Body>
                <Modal.Footer>
                    <Button style={styles.actionButton} variant="secondary" onClick={handleClose}>
                        Close
                    </Button>
                </Modal.Footer>
            </Modal>

        </div>
    );
};
const styles = {
    actionButton: {
        padding: "8px 12px",
        margin: "0 5px",
        backgroundColor: "rgb(76, 175, 80)",
        color: "#fff",
        border: "none",
        borderRadius: "4px",
        cursor: "pointer",
}
}
export default ScheduleCalendar;
